mapper.insert:
INSERT INTO MCP_REVIEW_PROMOTION
(
    REVIEW_PROMOTION_SEQ     --이벤트 참여 프로모션 일련번호 SQ_REVIEW_PROMOTION_SEQ SEQUENCE
     , PROMOTION_CODE           --프로모션 코드 공통코드 EventJoinInfo 01, 02 ....
     , USER_DIVISION            --회원구분 01 : 정회원 02:준회원 99:비회원
     , CONTRACT_NUM             --계약번호
     , USER_ID                  --회원아이디_등록 아이디
     , USE_TEL_CODE             --이용중 통신사 정보 공통코드 NSC  SKT : SKT ,  LGT : LG U+  ,  KTF : KT ,   ETC : 타알뜰폰(공통코드 없음)
     , REVIEW_CONTENT           --리뷰 내용
     , SYS_RDT                  --등록일
     , SYS_RDATE                --등록일시
     , RIP                      --등록자아이피
     , RVISN_ID                 --수정자ID
     , RVISN_DTTM               --수정일시
     , UIP                      --수정자아이피
     , NAME                     --인증 성명
     , MOBILE_NO                --인증 휴대폰번호
     , DUP_INFO                 -- DUP_INFO
     , REQ_SEQ                  -- 일련번호 기본키
     , RES_SEQ                  -- 요청 일련번호
     , CONN_INFO                -- CI
     , BIRTH_DATE               -- 생년월일
) VALUES (

    SQ_REVIEW_PROMOTION_SEQ.NEXTVAL
     , #{promotionCode}
     , #{userDivision}
     , #{contractNum}
     , #{userId}
     , #{useTelCode}
     , #{reviewContent}
     , TO_CHAR(SYSDATE, 'YYYYMMDD')
     , SYSDATE
     , #{rip}
     , #{rvisnId}
     , SYSDATE
     , #{uip}
     , #{name}
     , #{mobileNo}
     , #{dupInfo}
     , #{reqSeq}
     , #{resSeq}
     , #{connInfo}
     , #{birthDate}
)

mapper.select:
SELECT A.REVIEW_PROMOTION_SEQ , A.PROMOTION_CODE , A.USER_DIVISION , A.CONTRACT_NUM , A.USER_ID , A.USE_TEL_CODE , A.REVIEW_CONTENT , A.SHOW_YN , A.PRIZE_YN , A.INDC_ODRG , A.SYS_RDT , A.SYS_RDATE , A.RIP , A.RVISN_ID , A.RVISN_DTTM , A.UIP , A.NAME , A.MOBILE_NO , A.DUP_INFO , A.REQ_SEQ , A.RES_SEQ , B.DTL_CD_NM , B.UP_GRP_CD , A.CONN_INFO , A.BIRTH_DATE FROM MCP_REVIEW_PROMOTION A INNER JOIN NMCP_CD_DTL B ON A.PROMOTION_CODE = B.DTL_CD
WHERE 1=1
AND A.PROMOTION_CODE = #{promotionCode}
AND A.DUP_INFO = #{dupInfo}
AND A.MOBILE_NO = #{mobileNo}
AND B.CD_GROUP_ID = 'EventJoinInfo' AND B.USE_YN = 'Y' AND A.SHOW_YN = 'Y' AND A.USE_YN = 'Y' ORDER BY A.PRIZE_YN DESC, A.INDC_ODRG, A.REVIEW_PROMOTION_SEQ DESC

SELECT COUNT(1) AS CNT FROM MCP_REVIEW_PROMOTION A INNER JOIN NMCP_CD_DTL B ON A.PROMOTION_CODE = B.DTL_CD WHERE 1=1
AND PROMOTION_CODE = #{promotionCode}
AND DUP_INFO = #{dupInfo}
AND MOBILE_NO = #{mobileNo}
AND B.CD_GROUP_ID ='EventJoinInfo' AND B.USE_YN = 'Y' AND A.SHOW_YN = 'Y'
AND A.USE_YN = 'Y'

mapper.delete:
DELETE FROM MCP_REVIEW_PROMOTION
WHERE 1=1
AND REVIEW_PROMOTION_SEQ = #{reviewPromotionSeq}

AND DUP_INFO = #{dupInfo}

