AND DUP_INFO = #{dupInfo}

mapper.insert:
INSERT INTO MCP_SHARE_PROMOTION
(
     PROMOTION_CODE           -- 프로모션 코드 공통코드 EventJoinInfo 01, 02 ....
) VALUES (

    #{promotionCode}
)

INSERT INTO MCP_SHARE_PROMOTION
(
     PROMOTION_CODE           -- 프로모션 코드 공통코드 EventJoinInfo 01, 02 ....
    ,DUP_INFO
    ,SHARE_CNT
) VALUES (

    #{promotionCode}
    ,#{dupInfo}
    ,1
)

mapper.update:
UPDATE MCP_SHARE_PROMOTION SET
    SHARE_CNT = SHARE_CNT + 1
WHERE 1=1
AND PROMOTION_CODE = #{promotionCode}


       AND DUP_INFO = #{dupInfo}


       AND DUP_INFO IS NULL
